#!/usr/bin/env python3
"""Append Spanish translations to faq.ts"""

def ts_string(s):
    s = s.replace('\\', '\\\\')
    s = s.replace('"', '\\"')
    s = s.replace('\n', '\\n')
    return s

def section(title, body):
    return {"title": title, "body": body}

def write_lang(f, lang, sections):
    f.write(f'  "{lang}": [\n')
    for i, sec in enumerate(sections):
        t = ts_string(sec["title"])
        b = ts_string(sec["body"])
        f.write(f'    {{\n')
        f.write(f'      title: "{t}",\n')
        f.write(f'      body: "{b}",\n')
        f.write(f'    }},\n')
    f.write(f'  ],\n\n')

